import React,{useEffect,useCallback}from 'react'
import {ReactNavbar} from "react-responsive-animate-navbar";

const Navbar = () => {
    useEffect( () => {


        document.querySelectorAll("html body .styles_navLinks__38tON ul li").forEach(function (child) {
            // var a = document.getElementById(child);
            child.setAttribute("href", "#aboutme");
            child.addEventListener('click', (e) => {

                    window.scrollTo({
                        top: 400,
                        behavior: 'smooth',
                    })
                }
            );
            console.log("useEffect");

        });
        return() =>{
            document.querySelectorAll("html body .styles_navLinks__38tON ul li").forEach(function (child) {
                // var a = document.getElementById(child);
                child.setAttribute("href", "#aboutme");
                child.removeEventListener('click', (e) => {

                        window.scrollTo({
                            top: 400,
                            behavior: 'smooth',
                        })
                    }
                );
                console.log(child);
                child.click();
            });
        }
    });

    return (
        <div>
        <ReactNavbar
            color="rgb(25,100,50)"
            logo='logo-removebg-preview.png'

            menu={[
                { name: "HOME", to: "/" },
                { name: "ABOUT ME", to: "aboutme" },
                { name: "PROJECT", to: "project" },
                { name: "CONTACT", to: "contact" },
            ]}
            social={[
                {
                    name: "Linkedin",
                    url: "https://www.linkedin.com/in/daniel-lee-00991085",
                    icon: ["fab", "linkedin-in"],
                },
                {
                    name: "Github",
                    url: "https://github.com/DMZnoo",
                    icon: ["fab", "github"],
                }
            ]}

        />
        </div>
    )
};
export default Navbar;
